    async def test_pid_reuse_after_death_is_re_watched(self, db) -> None:
        """PID reused after its death has hooks newer than the death row.

        Watch set must include the tuple again so the new instance's
        eventual death gets its own pid_deaths row.
        """
        # Instance 1: hook + recorded death
        await _seed_hook(
            db,
            session_id="s-old",
            pid=4242,
            received_at=100.0,
            source_system="host-local",
        )
        await schema.insert_log_pid_death(
            db,
            pid=4242,
            source_system="host-local",
            cwd="/proj",
            observed_at=200.0,
            observed_by="pid-watcher",
        )
        # Instance 2: same PID reused after the recorded death
        await _seed_hook(
            db,
            session_id="s-new",
            pid=4242,
            received_at=300.0,
            source_system="host-local",
        )

        with (
            patch(
                "agentpulse.platforms.claude.pid_watcher.socket.gethostname",
                return_value="host-local",
            ),
            patch(
                "agentpulse.platforms.claude.pid_watcher._pid_exists",
                return_value=False,
            ),
            patch(
                "agentpulse.platforms.claude.pid_watcher.broadcast_pid_death_logged"
            ) as mock_bc,
        ):
            await run_pid_watcher_tick(db)

        cursor = await db.execute(
            "SELECT count(*) AS n FROM claude_log_pid_deaths "
            "WHERE pid = 4242 AND source_system = 'host-local' AND cwd = '/proj'"
        )
        # Original death + new death for the reused-PID instance
        assert dict(await cursor.fetchone())["n"] == 2
        mock_bc.assert_awaited_once()

